import { useState } from "react";

const Simulateur = () => {
  const [form, setForm] = useState({ zone: "", type_bien: "", type_offre: "VENTE", surface_m2: "", pieces: "" });
  const [result, setResult] = useState(null);

  const run = () => {
    const base = Number(form.surface_m2 || 0) * 150000;
    const ajust = Number(form.pieces || 0) * 1000000;
    const prix = base + ajust;
    setResult({
      prix_estime: prix,
      intervalle: [prix * 0.9, prix * 1.1],
      valeur_venale: prix * 0.85,
      indice_zone: "STABLE",
    });
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow space-y-3">
      <h2 className="text-2xl font-semibold">Simulateur IA</h2>
      <div className="grid md:grid-cols-5 gap-2">
        <input className="border p-2 rounded" placeholder="Zone" onChange={(e) => setForm({ ...form, zone: e.target.value })} />
        <input className="border p-2 rounded" placeholder="Type bien" onChange={(e) => setForm({ ...form, type_bien: e.target.value })} />
        <select className="border p-2 rounded" onChange={(e) => setForm({ ...form, type_offre: e.target.value })}><option>VENTE</option><option>LOCATION</option></select>
        <input className="border p-2 rounded" type="number" placeholder="Surface" onChange={(e) => setForm({ ...form, surface_m2: e.target.value })} />
        <input className="border p-2 rounded" type="number" placeholder="Pièces" onChange={(e) => setForm({ ...form, pieces: e.target.value })} />
      </div>
      <button className="bg-primary text-white px-4 py-2 rounded" onClick={run}>Estimer</button>
      {result && <div>
        <p>Prix estimé: {result.prix_estime.toLocaleString()} FCFA</p>
        <p>Intervalle: {result.intervalle[0].toLocaleString()} - {result.intervalle[1].toLocaleString()} FCFA</p>
        <p>Valeur vénale OTR: {result.valeur_venale.toLocaleString()} FCFA</p>
        <p>Indice zone: {result.indice_zone}</p>
      </div>}
    </div>
  );
};

export default Simulateur;
